UPDATE clients SET
    name = #{name}, business_reg_no = #{businessRegNo}, corporate_reg_no = #{corporateRegNo}, ceo_name = #{ceoName},
    industry = #{industry}, phone = #{phone}, email = #{email},
    zip_code = #{zipCode}, address = #{address}, address_detail = #{addressDetail},
    status = #{status}, memo = #{memo}
WHERE id = #{id}

UPDATE client_contacts SET
    name = #{name}, department = #{department}, position = #{position},
    phone = #{phone}, email = #{email}, is_primary = #{isPrimary}
WHERE id = #{id} AND client_id = #{clientId}
